-- All 70 demo branches — UUIDs follow canonical enterprise convention:
-- d0000000-0000-0000-0000-0000000000XX (hex branch_code).
-- Byte-identical to core7_enterprise.branches.id for the same codes.
ON CONFLICT (id) DO UPDATE
    SET branch_code = EXCLUDED.branch_code,
        name        = EXCLUDED.name,
        is_active   = EXCLUDED.is_active;
